import React, { useEffect, useState, useRef } from 'react';
import './App.css';
import { BrowserRouter, Routes, Route } from "react-router-dom";
import Home from './components/Home';
import Stories from './components/Stories';
import EventDetail from './components/EventDetail';
import Services from './components/Services';


function App() {

  const [scrollY, setScrollY] = useState(0);
  const [isLoaded, setIsLoaded] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);

  useEffect(() => {
    // Trigger load animation
    setTimeout(() => setIsLoaded(true), 100);

    const handleScroll = () => {
      setScrollY(window.scrollY);
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const scrollToSection = (id) => {
    const element = document.getElementById(id);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth' });
      setMenuOpen(false);
    }
  };

  return (
    // <div className={`app ${isLoaded ? 'loaded' : ''}`}>
    //   <Navigation scrollToSection={scrollToSection} menuOpen={menuOpen} setMenuOpen={setMenuOpen} />
    //   <Hero scrollY={scrollY} />
    //   <About scrollY={scrollY} />
    //   <Portfolio scrollY={scrollY} />
    //   <Stories />
    //   <Services />
    //   <Contact />
    //   <Footer />
    // </div>



    <BrowserRouter>

      <div className={`app ${isLoaded ? 'loaded' : ''}`}>
        <Routes>
          <Route path="/" element={<Hero scrollY={scrollY} />} />
          <Route path="/about" element={<About scrollY={scrollY} />} />
          <Route path="/portfolio" element={<Portfolio scrollY={scrollY} />} />
          <Route path="/stories" element={<Stories />} />
          <Route path="/event/:eventId" element={<EventDetail />} />
          <Route path="/home" element={<Home />} />
          <Route path="/services" element={<Services />} />
          <Route path="/contact" element={<Contact />} />
          {/* <Portfolio scrollY={scrollY} />
          <Stories />
          <Services />
          <Contact /> */}
        </Routes>
      </div>
    </BrowserRouter>
  );
}

// Hero Section with Parallax
function Hero({ scrollY }) {
  const parallaxOffset = scrollY * 0.5;

  return (
    <section id="hero" className="hero">
      <div
        className="hero-background"
        style={{ transform: `translateY(${parallaxOffset}px)` }}
      >
        <div className="hero-overlay"></div>
      </div>

      {/* <div className="hero-content">
        <p className="hero-tagline">You Feel. I Focus. We Frame.</p>
        <h1 className="hero-title">
          <span className="hero-line">Capturing</span>
          <span className="hero-line">Moments,</span>
          <span className="hero-line">Creating Stories</span>
        </h1>
        <div className="hero-cta">
          <a href="#portfolio" className="btn-primary">View Portfolio</a>
          <a href="#contact" className="btn-secondary">Get in Touch</a>
        </div>
      </div> */}

      <div className="hero-content">
        <p className="hero-tagline">You Feel. I Focus. We Frame.</p>
        {/* <h1 className="hero-title">
          <span className="hero-line">Capturing</span>
          <span className="hero-line">Moments,</span>
          <span className="hero-line">Creating Stories</span>
        </h1> */}
        <div className="hero-cta">
          {/* <a href="#portfolio" className="btn-primary">View Portfolio</a> */}
          <a href="/home" className="btn-secondary">Enter</a>
        </div>
      </div>
    </section>
  );
}

// About Section
function About({ scrollY }) {
  const sectionRef = useRef(null);
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true);
        }
      },
      { threshold: 0.2 }
    );

    if (sectionRef.current) {
      observer.observe(sectionRef.current);
    }

    return () => observer.disconnect();
  }, []);

  const parallaxOffset = scrollY * 0.1;

  return (
    <section id="about" className="about" ref={sectionRef}>
      <div className="about-container">
        <div className={`about-image-wrapper ${isVisible ? 'fade-in-left' : ''}`}>
          <div
            className="about-image"
            style={{ transform: `translateY(${-parallaxOffset}px)` }}
          >
            <div className="about-image-placeholder">
              <div className="placeholder-content">
                <span className="placeholder-text">Jay Dabgar</span>
              </div>
            </div>
          </div>
        </div>

        <div className={`about-content ${isVisible ? 'fade-in-right' : ''}`}>
          <p className="about-label">The Photographer</p>
          <h2 className="about-title">Creating Fiction out of Reality</h2>
          <div className="about-divider"></div>
          <p className="about-text">
            With over a decade of experience capturing life's most precious moments,
            I believe that every photograph tells a story. My approach combines
            documentary authenticity with artistic vision, creating images that
            are both timeless and emotionally resonant.
          </p>
          <p className="about-text">
            From intimate weddings to grand celebrations, I seek to capture the
            genuine connections and fleeting moments that make your story uniquely yours.
            Photography is not just about preserving memories—it's about creating art
            that will be treasured for generations.
          </p>
          <div className="about-stats">
            <div className="stat">
              <span className="stat-number">500+</span>
              <span className="stat-label">Weddings</span>
            </div>
            <div className="stat">
              <span className="stat-number">10+</span>
              <span className="stat-label">Years</span>
            </div>
            <div className="stat">
              <span className="stat-number">50+</span>
              <span className="stat-label">Awards</span>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

// Portfolio Section with Parallax Grid
function Portfolio({ scrollY }) {
  const sectionRef = useRef(null);
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true);
        }
      },
      { threshold: 0.1 }
    );

    if (sectionRef.current) {
      observer.observe(sectionRef.current);
    }

    return () => observer.disconnect();
  }, []);

  const portfolioItems = [
    { id: 1, category: 'Weddings', title: 'Eternal Love', size: 'large' },
    { id: 2, category: 'Portrait', title: 'Soul Stories', size: 'small' },
    { id: 3, category: 'Events', title: 'Celebrations', size: 'small' },
    { id: 4, category: 'Weddings', title: 'Sacred Bonds', size: 'medium' },
    { id: 5, category: 'Fashion', title: 'Editorial', size: 'small' },
    { id: 6, category: 'Weddings', title: 'Royal Affairs', size: 'medium' },
  ];

  return (
    <section id="portfolio" className="portfolio" ref={sectionRef}>
      <div className="section-header">
        <p className="section-label">Portfolio</p>
        <h2 className="section-title">Selected Works</h2>
        <div className="section-divider"></div>
      </div>

      <div className="portfolio-grid">
        {portfolioItems.map((item, index) => (
          <PortfolioItem
            key={item.id}
            item={item}
            index={index}
            scrollY={scrollY}
            isVisible={isVisible}
          />
        ))}
      </div>
    </section>
  );
}

function PortfolioItem({ item, index, scrollY, isVisible }) {
  const itemRef = useRef(null);
  const [itemOffset, setItemOffset] = useState(0);

  useEffect(() => {
    if (itemRef.current) {
      const rect = itemRef.current.getBoundingClientRect();
      setItemOffset(rect.top + window.scrollY);
    }
  }, []);

  const parallaxSpeed = 0.05 + (index % 3) * 0.02;
  const parallaxY = (scrollY - itemOffset) * parallaxSpeed;

  return (
    <div
      ref={itemRef}
      className={`portfolio-item ${item.size} ${isVisible ? 'fade-in-up' : ''}`}
      style={{ animationDelay: `${index * 0.1}s` }}
    >
      <div className="portfolio-image-wrapper">
        <div
          className="portfolio-image"
          style={{ transform: `translateY(${parallaxY}px) scale(1.1)` }}
        >
          <div className="portfolio-placeholder">
            <span>{item.title}</span>
          </div>
        </div>
        <div className="portfolio-overlay">
          <span className="portfolio-category">{item.category}</span>
          <h3 className="portfolio-item-title">{item.title}</h3>
          <button className="portfolio-view">View Gallery</button>
        </div>
      </div>
    </div>
  );
}

